  const frontmatter = {};
  for (const line of fmMatch[1].split("\n")) {
    const kv = line.match(/^(\w[\w\s]*?):\s*(.+)$/);
    if (!kv) continue;
    const key = kv[1].trim().toLowerCase().replace(/\s+/g, "");
    const val = kv[2].trim().replace(/^['"]|['"]$/g, "");
    frontmatter[key] = val;
  }
