// src/index.ts
function createApp() {
  const app2 = new Hono2();
  app2.use(
    "*",
    cors({
      origin: (origin) => {
        const allowed = [
          /^https?:\/\/localhost(:\d+)?$/,
          /^https?:\/\/127\.0\.0\.1(:\d+)?$/,
          /^https?:\/\/tauri\.localhost(:\d+)?$/,
          /^tauri:\/\/localhost$/,
          /^https?:\/\/localhost\.tauri\.app$/
        ];
        if (!origin || allowed.some((p) => p.test(origin))) return origin;
        return null;
      },
      allowMethods: ["GET", "POST", "PUT", "DELETE", "OPTIONS"],
      allowHeaders: ["Content-Type", "x-cabinet-pin"],
      maxAge: 86400
    })
  );
  app2.use("/api/*", rateLimiter(100, 6e4));
  app2.use("/api/auth/verify", rateLimiter(5, 6e4));
  app2.use("/api/*", authMiddleware);
  app2.route("/health", healthRouter);
  app2.route("/.well-known", agentsRouter);
  app2.route("/api/agents", agentsRouter);
  app2.route("/api/projects", projectsRouter);
  app2.route("/api/secretary", secretaryRouter);
  app2.route("/api/decisions", decisionsRouter);
  app2.route("/api/meetings", meetingsRouter);
  app2.route("/api/factory", workflowsRouter);
  app2.route("/api/dashboard", dashboardRouter);
  app2.route("/api/settings", settingsRouter);
  app2.route("/api/auth", authRouter);
  app2.route("/api/skills", skillsRouter);
  app2.route("/api/memory", memoryRouter);
  app2.route("/api/employees", employeesRouter);
  app2.route("/api/files", filesRouter);
  app2.route("/api/audit", auditRouter);
  app2.route("/api/backups", backupsRouter);
  app2.route("/api/gc", gcRouter);
  app2.route("/api/verify", verifyRouter);
  app2.route("/api/rules", rulesRouter);
  app2.route("/api/progress", progressRouter);
  app2.route("/api/observability", observabilityRouter);
  app2.route("/api", openapiRouter());
  return app2;
}

